    def advance(self):
        if not self.stopped():
            self.cur_x += self.dx
            self.cur_y += self.dy

    def cross(self, other):
        # 每次判断是否相遇时需要重置 cur
        self.reset()
        other.reset()
        while not self.stopped() or not other.stopped():
            self.advance()
            other.advance()
            if self.cur_x == other.cur_x and self.cur_y == other.cur_y:
